figma.showUI(__html__, { themeColors: true, width: 300, height: 300 });

const START_ANGLE = Math.PI; 
const FULL_ARC = Math.PI;    

// --- 1. DEFINIÇÃO DE DADOS ---

interface ChartSettings {
  gapEnabled: boolean;
}
const DEFAULT_SETTINGS: ChartSettings = { gapEnabled: true };

interface ChartValues {
  [id: number]: number;
}

interface VariantOption {
  value: string;
  label: string;
  hex: string;
}

interface DataNodeCache {
  container: SceneNode;
  changeFillInstance: InstanceNode | null;
  maskEllipse: EllipseNode | null;
  lastKnownVariant: string | null;
  cachedVariantOptions: VariantOption[];
  percentage: number; 
  lastKnownArcSpan: number;
}

let currentChartCache: {
  node: InstanceNode;
  dataMap: Map<number, DataNodeCache>;
  settings: ChartSettings;
  defaultGapPercentage: number;
  bgNode: SceneNode | null;
  bgVisible: boolean;
  arrowNode: SceneNode | null;
  arrowVisible: boolean;
  valueSectionNode: SceneNode | null;
  valueSectionVisible: boolean;
} | null = null;

let pollingInterval: number | null = null;

// --- 2. CONFIGURAÇÃO DE PRESETS ---

// Estrutura de dados para um Preset
interface PresetConfig {
  id: string;
  name: string;
  imgUrl: string; // URL da imagem (Vazio usa o nome como texto)
  settings: {
    gapEnabled: boolean;
    bgVisible: boolean;
    arrowVisible: boolean;
    valueSectionVisible: boolean;
  };
  items: {
    id: number;     // Qual #data será afetado
    percentage: number;
    variantValue: string; // Ex: "1", "2"
  }[];
}

// O BANCO DE DADOS DE PRESETS
